   1	import {
   2	  Radio,
   3	  Checkbox,
   4	  Tooltip,
   5	  TooltipPosition,
   6	  Dropdown,
   7	  DropdownList,
   8	  MenuToggleElement,
   9	  MenuToggle
  10	} from '@patternfly/react-core';
  11	import * as React from 'react';
  12	import { connect } from 'react-redux';
  13	import { bindActionCreators } from 'redux';
  14	import { HistoryManager, URLParam } from '../../../app/History';
  15	import { GraphToolbarState, KialiAppState } from '../../../store/Store';
  16	import { GraphToolbarActions } from '../../../actions/GraphToolbarActions';
  17	import { GraphType, EdgeLabelMode, isResponseTimeMode, isThroughputMode, RankMode } from '../../../types/Graph';
  18	import { startCase } from 'lodash-es';
  19	import { edgeLabelsSelector } from 'store/Selectors';
  20	import {
  21	  BoundingClientAwareComponent,
  22	  PropertyType
  23	} from 'components/BoundingClientAwareComponent/BoundingClientAwareComponent';
  24	import { KialiIcon } from 'config/KialiIcon';
  25	import {
  26	  containerStyle,
  27	  itemStyleWithInfo,
  28	  itemStyleWithoutInfo,
  29	  menuStyle,
  30	  menuEntryStyle,
  31	  titleStyle
  32	} from 'styles/DropdownStyles';
  33	import { INITIAL_GRAPH_STATE } from 'reducers/GraphDataState';
  34	import { KialiDispatch } from 'types/Redux';
  35	import { KialiCrippledFeatures } from 'types/ServerConfig';
  36	import { getCrippledFeatures } from 'services/Api';
  37	import { serverConfig } from '../../../config';
  38	import { infoStyle } from 'styles/IconStyle';
  39	
  40	type ReduxStateProps = {
  41	  boxByCluster: boolean;
  42	  boxByNamespace: boolean;
  43	  edgeLabels: EdgeLabelMode[];
  44	  rankBy: RankMode[];
  45	  showIdleEdges: boolean;
  46	  showIdleNodes: boolean;
  47	  showOperationNodes: boolean;
  48	  showOutOfMesh: boolean;
  49	  showRank: boolean;
  50	  showSecurity: boolean;
  51	  showServiceNodes: boolean;
  52	  showTrafficAnimation: boolean;
  53	  showVirtualServices: boolean;
  54	  showWaypoints: boolean;
  55	};
  56	
  57	type ReduxDispatchProps = {
  58	  setEdgeLabels: (edgeLabels: EdgeLabelMode[]) => void;
  59	  setRankBy: (rankBy: RankMode[]) => void;
  60	  toggleBoxByCluster(): void;
  61	  toggleBoxByNamespace(): void;
  62	  toggleGraphMissingSidecars(): void;
  63	  toggleGraphSecurity(): void;
  64	  toggleGraphVirtualServices(): void;
  65	  toggleIdleEdges(): void;
  66	  toggleIdleNodes(): void;
  67	  toggleOperationNodes(): void;
  68	  toggleRank(): void;
  69	  toggleServiceNodes(): void;
  70	  toggleTrafficAnimation(): void;
  71	  toggleWaypoints(): void;
  72	};
  73	
  74	type GraphSettingsProps = ReduxStateProps &
  75	  ReduxDispatchProps &
  76	  Omit<GraphToolbarState, 'findValue' | 'hideValue' | 'showLegend' | 'showFindHelp' | 'trafficRates'> & {
  77	    disabled: boolean;
  78	  };
  79	
  80	type GraphSettingsState = { crippledFeatures?: KialiCrippledFeatures; isOpen: boolean };
  81	
  82	interface DisplayOptionType {
  83	  iconClassName?: string;
  84	  iconColor?: string;
  85	  id: string;
  86	  isChecked: boolean;
  87	  isDisabled?: boolean;
  88	  labelText: string;
  89	  onChange?: () => void;
  90	  tooltip?: React.ReactNode;
  91	}
  92	
  93	const marginBottom = 20;
  94	
  95	class GraphSettingsComponent extends React.PureComponent<GraphSettingsProps, GraphSettingsState> {
  96	  constructor(props: GraphSettingsProps) {
  97	    super(props);
  98	
  99	    this.state = {
 100	      isOpen: false
 101	    };
 102	
 103	    // Let URL override current redux state at construction time. Update URL as needed.
 104	    this.handleURLBool(
 105	      URLParam.GRAPH_ANIMATION,
 106	      INITIAL_GRAPH_STATE.toolbarState.showTrafficAnimation,
 107	      props.showTrafficAnimation,
 108	      props.toggleTrafficAnimation
 109	    );
 110	
 111	    this.handleURLBool(
 112	      URLParam.GRAPH_BADGE_SECURITY,
 113	      INITIAL_GRAPH_STATE.toolbarState.showSecurity,
 114	      props.showSecurity,
 115	      props.toggleGraphSecurity
 116	    );
 117	
 118	    this.handleURLBool(
 119	      URLParam.GRAPH_BADGE_SIDECAR,
 120	      INITIAL_GRAPH_STATE.toolbarState.showOutOfMesh,
 121	      props.showOutOfMesh,
 122	      props.toggleGraphMissingSidecars
 123	    );
 124	
 125	    this.handleURLBool(
 126	      URLParam.GRAPH_BADGE_VS,
 127	      INITIAL_GRAPH_STATE.toolbarState.showVirtualServices,
 128	      props.showVirtualServices,
 129	      props.toggleGraphVirtualServices
 130	    );
 131	
 132	    this.handleURLBool(
 133	      URLParam.GRAPH_BOX_CLUSTER,
 134	      INITIAL_GRAPH_STATE.toolbarState.boxByCluster,
 135	      props.boxByCluster,
 136	      props.toggleBoxByCluster
 137	    );
 138	
 139	    this.handleURLBool(
 140	      URLParam.GRAPH_BOX_NAMESPACE,
 141	      INITIAL_GRAPH_STATE.toolbarState.boxByNamespace,
 142	      props.boxByNamespace,
 143	      props.toggleBoxByNamespace
 144	    );
 145	
 146	    this.handleURLBool(
 147	      URLParam.GRAPH_IDLE_EDGES,
 148	      INITIAL_GRAPH_STATE.toolbarState.showIdleEdges,
 149	      props.showIdleEdges,
 150	      props.toggleIdleEdges
 151	    );
 152	
 153	    this.handleURLBool(
 154	      URLParam.GRAPH_IDLE_NODES,
 155	      INITIAL_GRAPH_STATE.toolbarState.showIdleNodes,
 156	      props.showIdleNodes,
 157	      props.toggleIdleNodes
 158	    );
 159	
 160	    this.handleURLBool(
 161	      URLParam.GRAPH_OPERATION_NODES,
 162	      INITIAL_GRAPH_STATE.toolbarState.showOperationNodes,
 163	      props.showOperationNodes,
 164	      props.toggleOperationNodes
 165	    );
 166	
 167	    this.handleURLBool(
 168	      URLParam.GRAPH_RANK,
 169	      INITIAL_GRAPH_STATE.toolbarState.showRank,
 170	      props.showRank,
 171	      props.toggleRank
 172	    );
 173	
 174	    this.handleURLBool(
 175	      URLParam.GRAPH_SERVICE_NODES,
 176	      INITIAL_GRAPH_STATE.toolbarState.showServiceNodes,
 177	      props.showServiceNodes,
 178	      props.toggleServiceNodes
 179	    );
 180	
 181	    this.handleURLBool(
 182	      URLParam.GRAPH_WAYPOINTS,
 183	      INITIAL_GRAPH_STATE.toolbarState.showWaypoints,
 184	      props.showWaypoints,
 185	      props.toggleWaypoints
 186	    );
 187	  }
 188	
 189	  componentDidMount(): void {
 190	    getCrippledFeatures().then(response => {
 191	      const crippledFeatures = response.data;
 192	      this.setState({ crippledFeatures: response.data });
 193	
 194	      // strip away any invalid edge options from the url
 195	      if (
 196	        (crippledFeatures.responseTime || crippledFeatures.responseTimePercentiles) &&
 197	        this.props.edgeLabels.some(l => isResponseTimeMode(l))
 198	      ) {
 199	        this.props.setEdgeLabels(this.props.edgeLabels.filter(l => !isResponseTimeMode(l)));
 200	      }
 201	
 202	      if (
 203	        (crippledFeatures.requestSize && this.props.edgeLabels.includes(EdgeLabelMode.THROUGHPUT_REQUEST)) ||
 204	        (crippledFeatures.responseSize && this.props.edgeLabels.includes(EdgeLabelMode.THROUGHPUT_RESPONSE))
 205	      ) {
 206	        this.props.setEdgeLabels(this.props.edgeLabels.filter(l => !isThroughputMode(l)));
 207	      }
 208	    });
 209	  }
 210	
 211	  componentDidUpdate(prev: GraphSettingsProps): void {
 212	    // ensure redux state and URL are aligned
 213	    this.alignURLBool(
 214	      URLParam.GRAPH_ANIMATION,
 215	      INITIAL_GRAPH_STATE.toolbarState.showTrafficAnimation,
 216	      prev.showTrafficAnimation,
 217	      this.props.showTrafficAnimation
 218	    );
 219	
 220	    this.alignURLBool(
 221	      URLParam.GRAPH_BADGE_SECURITY,
 222	      INITIAL_GRAPH_STATE.toolbarState.showSecurity,
 223	      prev.showSecurity,
 224	      this.props.showSecurity
 225	    );
 226	
 227	    this.alignURLBool(
 228	      URLParam.GRAPH_BADGE_SIDECAR,
 229	      INITIAL_GRAPH_STATE.toolbarState.showOutOfMesh,
 230	      prev.showOutOfMesh,
 231	      this.props.showOutOfMesh
 232	    );
 233	
 234	    this.alignURLBool(
 235	      URLParam.GRAPH_BADGE_VS,
 236	      INITIAL_GRAPH_STATE.toolbarState.showVirtualServices,
 237	      prev.showVirtualServices,
 238	      this.props.showVirtualServices
 239	    );
 240	
 241	    this.alignURLBool(
 242	      URLParam.GRAPH_BOX_CLUSTER,
 243	      INITIAL_GRAPH_STATE.toolbarState.boxByCluster,
 244	      prev.boxByCluster,
 245	      this.props.boxByCluster
 246	    );
 247	
 248	    this.alignURLBool(
 249	      URLParam.GRAPH_BOX_NAMESPACE,
 250	      INITIAL_GRAPH_STATE.toolbarState.boxByNamespace,
 251	      prev.boxByNamespace,
 252	      this.props.boxByNamespace
 253	    );
 254	
 255	    this.alignURLBool(
 256	      URLParam.GRAPH_IDLE_EDGES,
 257	      INITIAL_GRAPH_STATE.toolbarState.showIdleEdges,
 258	      prev.showIdleEdges,
 259	      this.props.showIdleEdges
 260	    );
 261	
 262	    this.alignURLBool(
 263	      URLParam.GRAPH_IDLE_NODES,
 264	      INITIAL_GRAPH_STATE.toolbarState.showIdleNodes,
 265	      prev.showIdleNodes,
 266	      this.props.showIdleNodes
 267	    );
 268	
 269	    this.alignURLBool(
 270	      URLParam.GRAPH_OPERATION_NODES,
 271	      INITIAL_GRAPH_STATE.toolbarState.showOperationNodes,
 272	      prev.showOperationNodes,
 273	      this.props.showOperationNodes
 274	    );
 275	
 276	    this.alignURLBool(
 277	      URLParam.GRAPH_RANK,
 278	      INITIAL_GRAPH_STATE.toolbarState.showRank,
 279	      prev.showRank,
 280	      this.props.showRank
 281	    );
 282	
 283	    this.alignURLBool(
 284	      URLParam.GRAPH_SERVICE_NODES,
 285	      INITIAL_GRAPH_STATE.toolbarState.showServiceNodes,
 286	      prev.showServiceNodes,
 287	      this.props.showServiceNodes
 288	    );
 289	
 290	    this.alignURLBool(
 291	      URLParam.GRAPH_WAYPOINTS,
 292	      INITIAL_GRAPH_STATE.toolbarState.showWaypoints,
 293	      prev.showWaypoints,
 294	      this.props.showWaypoints
 295	    );
 296	  }
 297	
 298	  private handleURLBool = (
 299	    param: URLParam,
 300	    paramDefault: boolean,
 301	    reduxValue: boolean,
 302	    reduxToggle: () => void
 303	  ): void => {
 304	    const urlValue = HistoryManager.getBooleanParam(param);
 305	
 306	    if (urlValue !== undefined) {
 307	      if (urlValue !== reduxValue) {
 308	        reduxToggle();
 309	      }
 310	    } else if (reduxValue !== paramDefault) {
 311	      HistoryManager.setParam(param, String(reduxValue));
 312	    }
 313	  };
 314	
 315	  private alignURLBool = (param: URLParam, paramDefault: boolean, prev: boolean, curr: boolean): void => {
 316	    if (prev === curr) {
 317	      return;
 318	    }
 319	
 320	    if (curr === paramDefault) {
 321	      HistoryManager.deleteParam(param);
 322	    } else {
 323	      HistoryManager.setParam(param, String(curr));
 324	    }
 325	  };
 326	
 327	  render(): React.ReactNode {
 328	    return (
 329	      <Dropdown
 330	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 331	          <MenuToggle
 332	            ref={toggleRef}
 333	            id="display-settings"
 334	            onClick={() => this.onToggle(!this.state.isOpen)}
 335	            isExpanded={this.state.isOpen}
 336	            isDisabled={this.props.disabled}
 337	          >
 338	            Display
 339	          </MenuToggle>
 340	        )}
 341	        isOpen={this.state.isOpen}
 342	        onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
 343	      >
 344	        <DropdownList>{this.getMenuOptions()}</DropdownList>
 345	      </Dropdown>
 346	    );
 347	  }
 348	
 349	  private onToggle = (isOpen: boolean): void => {
 350	    this.setState({
 351	      isOpen
 352	    });
 353	  };
 354	
 355	  private getMenuOptions = (): React.ReactNode => {
 356	    // map our attributes from redux
 357	    const {
 358	      boxByCluster,
 359	      boxByNamespace,
 360	      edgeLabels,
 361	      showRank: rank,
 362	      rankBy: rankLabels,
 363	      showIdleEdges,
 364	      showIdleNodes,
 365	      showOutOfMesh,
 366	      showOperationNodes,
 367	      showSecurity,
 368	      showServiceNodes,
 369	      showTrafficAnimation,
 370	      showVirtualServices,
 371	      showWaypoints
 372	    } = this.props;
 373	
 374	    // map our dispatchers for redux
 375	    const {
 376	      toggleBoxByCluster,
 377	      toggleBoxByNamespace,
 378	      toggleGraphMissingSidecars,
 379	      toggleGraphSecurity,
 380	      toggleGraphVirtualServices,
 381	      toggleIdleEdges,
 382	      toggleIdleNodes,
 383	      toggleOperationNodes,
 384	      toggleRank,
 385	      toggleServiceNodes,
 386	      toggleTrafficAnimation,
 387	      toggleWaypoints
 388	    } = this.props;
 389	
 390	    const edgeLabelOptions: DisplayOptionType[] = [
 391	      {
 392	        id: EdgeLabelMode.RESPONSE_TIME_GROUP,
 393	        isChecked: edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_GROUP),
 394	        isDisabled:
 395	          this.state.crippledFeatures?.responseTime ||
 396	          (this.state.crippledFeatures?.responseTimeAverage && this.state.crippledFeatures?.responseTimePercentiles),
 397	        labelText: startCase(EdgeLabelMode.RESPONSE_TIME_GROUP),
 398	        tooltip: (
 399	          <div style={{ textAlign: 'left' }}>
 400	            <div>
 401	              Displays the requested response time. The unit is milliseconds (ms) when less than 1000, otherwise seconds
 402	              (s). Default: 95th Percentile.
 403	            </div>
 404	            <div>
 405	              Response times only apply to request-based traffic (not TCP or gRPC messaging). Additionally, the
 406	              following edges do not offer a response time label but the information is available in the side panel when
 407	              selecting the edge:
 408	            </div>
 409	            <div>- edges into service nodes</div>
 410	            <div>- edges into or out of operation nodes.</div>
 411	            <div>
 412	              This option will be disabled if response time telemetry is unavailable. Some options may be disabled for
 413	              the same reason.
 414	            </div>
 415	          </div>
 416	        )
 417	      },
 418	      {
 419	        id: EdgeLabelMode.THROUGHPUT_GROUP,
 420	        isChecked: edgeLabels.includes(EdgeLabelMode.THROUGHPUT_GROUP),
 421	        isDisabled: this.state.crippledFeatures?.requestSize && this.state.crippledFeatures?.responseSize,
 422	        labelText: startCase(EdgeLabelMode.THROUGHPUT_GROUP),
 423	        tooltip: (
 424	          <div style={{ textAlign: 'left' }}>
 425	            <div>
 426	              Displays the requested HTTP Throughput. The unit is bytes-per-second (bps) when less than 1024, otherwise
 427	              kilobytes-per-second (kps). Default: Request Throughput
 428	            </div>
 429	            <div>
 430	              Throughput applies only to request-based, HTTP traffic. Additionally, the following edges do not offer a
 431	              throughput label:
 432	            </div>
 433	            <div>- edges into service nodes</div>
 434	            <div>- edges into or out of operation nodes.</div>
 435	            <div>
 436	              This option will be disabled if throughput telemetry is unavailable. Some options may be disabled for the
 437	              same reason.
 438	            </div>
 439	          </div>
 440	        )
 441	      },
 442	      {
 443	        id: EdgeLabelMode.TRAFFIC_DISTRIBUTION,
 444	        isChecked: edgeLabels.includes(EdgeLabelMode.TRAFFIC_DISTRIBUTION),
 445	        labelText: startCase(EdgeLabelMode.TRAFFIC_DISTRIBUTION),
 446	        tooltip: (
 447	          <div style={{ textAlign: 'left' }}>
 448	            HTTP and gRPC Edges display the percentage of traffic for that edge, when less than 100%. For a source node,
 449	            the sum for outbound edges (per protocol) should be equal to or near 100%, given rounding. TCP edges are not
 450	            included in the distribution because their rates reflect bytes.
 451	          </div>
 452	        )
 453	      },
 454	      {
 455	        id: EdgeLabelMode.TRAFFIC_RATE,
 456	        isChecked: edgeLabels.includes(EdgeLabelMode.TRAFFIC_RATE),
 457	        labelText: startCase(EdgeLabelMode.TRAFFIC_RATE),
 458	        tooltip: (
 459	          <div style={{ textAlign: 'left' }}>
 460	            HTTP rates are in requests-per-second (rps). gRPC rates may be in requests-per-second (rps) or
 461	            messages-per-second (mps). For request rates, the percentage of error responses is shown below the rate,
 462	            when non-zero. TCP rates are in bytes. The unit is bytes-per-second (bps) when less than 1024, otherwise
 463	            kilobytes-per-second (kps). Rates are rounded to 2 significant digits.
 464	          </div>
 465	        )
 466	      }
 467	    ];
 468	
 469	    const throughputOptions: DisplayOptionType[] = [
 470	      {
 471	        id: EdgeLabelMode.THROUGHPUT_REQUEST,
 472	        isChecked: edgeLabels.includes(EdgeLabelMode.THROUGHPUT_REQUEST) && !this.state.crippledFeatures?.requestSize,
 473	        isDisabled: this.state.crippledFeatures?.requestSize,
 474	        labelText: 'Request',
 475	        tooltip: (
 476	          <div style={{ textAlign: 'left' }}>
 477	            HTTP request data in bytes-per-second (bps) or kilobytes-per-second (kps)
 478	          </div>
 479	        )
 480	      },
 481	      {
 482	        id: EdgeLabelMode.THROUGHPUT_RESPONSE,
 483	        isChecked: edgeLabels.includes(EdgeLabelMode.THROUGHPUT_RESPONSE) && !this.state.crippledFeatures?.responseSize,
 484	        isDisabled: this.state.crippledFeatures?.responseSize,
 485	        labelText: 'Response',
 486	        tooltip: (
 487	          <div style={{ textAlign: 'left' }}>
 488	            HTTP response data in bytes per second (bps) or kilobytes-per-second (kps)
 489	          </div>
 490	        )
 491	      }
 492	    ];
 493	
 494	    const responseTimeOptions: DisplayOptionType[] = [
 495	      {
 496	        id: EdgeLabelMode.RESPONSE_TIME_AVERAGE,
 497	        labelText: 'Average',
 498	        isChecked: edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_AVERAGE),
 499	        isDisabled: this.state.crippledFeatures?.responseTimeAverage,
 500	        tooltip: <div style={{ textAlign: 'left' }}>Average request response time</div>
 501	      },
 502	      {
 503	        id: EdgeLabelMode.RESPONSE_TIME_P50,
 504	        labelText: 'Median',
 505	        isChecked: edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_P50),
 506	        isDisabled: this.state.crippledFeatures?.responseTimePercentiles,
 507	        tooltip: <div style={{ textAlign: 'left' }}>Median request response time (50th Percentile)</div>
 508	      },
 509	      {
 510	        id: EdgeLabelMode.RESPONSE_TIME_P95,
 511	        labelText: '95th Percentile',
 512	        isChecked: edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_P95),
 513	        isDisabled: this.state.crippledFeatures?.responseTimePercentiles,
 514	        tooltip: <div style={{ textAlign: 'left' }}>Max response time for 95% of requests (95th Percentile)</div>
 515	      },
 516	      {
 517	        id: EdgeLabelMode.RESPONSE_TIME_P99,
 518	        labelText: '99th Percentile',
 519	        isChecked: edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_P99),
 520	        isDisabled: this.state.crippledFeatures?.responseTimePercentiles,
 521	        tooltip: <div style={{ textAlign: 'left' }}>Max response time for 99% of requests (99th Percentile)</div>
 522	      }
 523	    ];
 524	
 525	    const visibilityOptions: DisplayOptionType[] = [
 526	      {
 527	        id: 'boxByCluster',
 528	        isChecked: boxByCluster,
 529	        labelText: 'Cluster Boxes',
 530	        onChange: toggleBoxByCluster,
 531	        tooltip: (
 532	          <div style={{ textAlign: 'left' }}>
 533	            When enabled and there are multiple clusters, the graph will box nodes in the same cluster. This option is
 534	            ignored for layouts that don't support boxing. The "unknown" cluster is never boxed.
 535	          </div>
 536	        )
 537	      },
 538	      {
 539	        id: 'boxByNamespace',
 540	        isChecked: boxByNamespace,
 541	        labelText: 'Namespace Boxes',
 542	        onChange: toggleBoxByNamespace,
 543	        tooltip: (
 544	          <div style={{ textAlign: 'left' }}>
 545	            When enabled and there are multiple namespaces, the graph will box nodes in the same namespace, within the
 546	            same cluster. This option is ignored for layouts that don't support boxing. The "unknown" namespace is never
 547	            boxed.
 548	          </div>
 549	        )
 550	      },
 551	      {
 552	        id: 'filterIdleEdges',
 553	        isChecked: showIdleEdges,
 554	        labelText: 'Idle Edges',
 555	        onChange: toggleIdleEdges,
 556	        tooltip: (
 557	          <div style={{ textAlign: 'left' }}>
 558	            Idle edges have no request traffic for the time period. Disabled by default to provide cleaner graphs.
 559	            Enable to help detect unexpected traffic omissions, or to confirm expected edges with no traffic (due to
 560	            routing, mirroring, etc).
 561	          </div>
 562	        )
 563	      },
 564	      {
 565	        id: 'filterIdleNodes',
 566	        isChecked: showIdleNodes,
 567	        labelText: 'Idle Nodes',
 568	        onChange: toggleIdleNodes,
 569	        tooltip: (
 570	          <div style={{ textAlign: 'left' }}>
 571	            With "Idle Edges" enabled this displays nodes for defined services that have *never* received traffic. With
 572	            "Idle Edges" disabled this displays nodes for defined services that have not received traffic during the
 573	            current time period. Disabled by default to provide cleaner graphs. Enable to help locate unused,
 574	            misconfigured or obsolete services.
 575	          </div>
 576	        )
 577	      },
 578	      {
 579	        id: 'filterOperationNodes',
 580	        isChecked: showOperationNodes,
 581	        isDisabled: this.props.graphType === GraphType.SERVICE,
 582	        labelText: 'Operation Nodes',
 583	        onChange: toggleOperationNodes,
 584	        tooltip: (
 585	          <div style={{ textAlign: 'left' }}>
 586	            <div>
 587	              When both operation and service nodes are enabled then the operation is displayed specific to each service
 588	              to which it applies, and therefore may be duplicated for different services. When enabled independently
 589	              each operation will have a single node representing the total traffic for that operation.
 590	            </div>
 591	            <div>- Operations with no traffic are ignored.</div>
 592	            <div>- This is not applicable to Service graphs.</div>
 593	            <div>
 594	              - Operation nodes require additional "Request Classification" Istio configuration for workloads in the
 595	              selected namespaces.
 596	            </div>
 597	          </div>
 598	        )
 599	      },
 600	      {
 601	        id: 'rank',
 602	        isChecked: rank,
 603	        labelText: 'Rank',
 604	        onChange: toggleRank,
 605	        tooltip: (
 606	          <div style={{ textAlign: 'left' }}>
 607	            Rank graph nodes based on configurable criteria such as 'number of inbound edges'. These rankings can be
 608	            used in the graph find/hide feature to help highlight the most important workloads, services, and
 609	            applications. Rankings are normalized to fit between 1..100 and nodes may tie with each other in rank.
 610	            Ranking starts at 1 for the top ranked nodes so when ranking nodes based on 'number of inbound edges', the
 611	            node(s) with the most inbound edges would have rank 1. Node(s) with the second most inbound edges would have
 612	            rank 2. Each selected criteria contributes equally to a node's ranking. Although 100 rankings are possible,
 613	            only the required number of rankings are assigned, starting at 1.
 614	          </div>
 615	        )
 616	      },
 617	      {
 618	        id: 'filterServiceNodes',
 619	        isChecked: showServiceNodes,
 620	        isDisabled: this.props.graphType === GraphType.SERVICE,
 621	        labelText: 'Service Nodes',
 622	        onChange: toggleServiceNodes,
 623	        tooltip: (
 624	          <div style={{ textAlign: 'left' }}>
 625	            Reflect service routing by injecting the destination service nodes into the graph. This can be useful for
 626	            grouping requests for the same service, but routed to different workloads. Edges leading into service nodes
 627	            are logical aggregations and will not show response time labels, but if selected the side panel will provide
 628	            a response time chart.
 629	          </div>
 630	        )
 631	      },
 632	      {
