 298	  private handleURLBool = (
 299	    param: URLParam,
 300	    paramDefault: boolean,
 301	    reduxValue: boolean,
 302	    reduxToggle: () => void
 303	  ): void => {
 304	    const urlValue = HistoryManager.getBooleanParam(param);
 305	
 306	    if (urlValue !== undefined) {
 307	      if (urlValue !== reduxValue) {
 308	        reduxToggle();
 309	      }
 310	    } else if (reduxValue !== paramDefault) {
 311	      HistoryManager.setParam(param, String(reduxValue));
 312	    }
 313	  };
 314	
 315	  private alignURLBool = (param: URLParam, paramDefault: boolean, prev: boolean, curr: boolean): void => {
 316	    if (prev === curr) {
 317	      return;
 318	    }
 319	
 320	    if (curr === paramDefault) {
 321	      HistoryManager.deleteParam(param);
 322	    } else {
 323	      HistoryManager.setParam(param, String(curr));
 324	    }
 325	  };
