 948	  private toggleEdgeLabelMode = (event: React.FormEvent): void => {
 949	    const mode = (event.target as HTMLInputElement).value as EdgeLabelMode;
 950	
 951	    if (this.props.edgeLabels.includes(mode)) {
 952	      let newEdgeLabels: EdgeLabelMode[];
 953	
 954	      switch (mode) {
 955	        case EdgeLabelMode.RESPONSE_TIME_GROUP:
 956	          newEdgeLabels = this.props.edgeLabels.filter(l => !isResponseTimeMode(l));
 957	          break;
 958	        case EdgeLabelMode.THROUGHPUT_GROUP:
 959	          newEdgeLabels = this.props.edgeLabels.filter(l => !isThroughputMode(l));
 960	          break;
 961	        default:
 962	          newEdgeLabels = this.props.edgeLabels.filter(l => l !== mode);
 963	      }
 964	
 965	      this.props.setEdgeLabels(newEdgeLabels);
 966	    } else {
 967	      switch (mode) {
 968	        case EdgeLabelMode.RESPONSE_TIME_GROUP:
 969	          this.props.setEdgeLabels([
 970	            ...this.props.edgeLabels,
 971	            mode,
 972	            this.state.crippledFeatures?.responseSizePercentiles
 973	              ? EdgeLabelMode.RESPONSE_TIME_AVERAGE
 974	              : EdgeLabelMode.RESPONSE_TIME_P95
 975	          ]);
 976	          break;
 977	        case EdgeLabelMode.THROUGHPUT_GROUP:
 978	          this.props.setEdgeLabels([
 979	            ...this.props.edgeLabels,
 980	            mode,
 981	            this.state.crippledFeatures?.requestSize
 982	              ? EdgeLabelMode.THROUGHPUT_RESPONSE
 983	              : EdgeLabelMode.THROUGHPUT_REQUEST
 984	          ]);
 985	          break;
 986	        default:
 987	          this.props.setEdgeLabels([...this.props.edgeLabels, mode]);
 988	      }
 989	    }
